import{join}from"../util/path.js";import{_require}from"../util/require.js";export const loadPackageManifest=({dir:r,packageName:e,cwd:t})=>{try{return _require(join(r,"node_modules",e,"package.json"))}catch(o){if(r!==t)try{return _require(join(t,"node_modules",e,"package.json"))}catch(r){}}};export const getFilteredScripts=r=>{if(!r)return[{},{}];const e={},t={};for(const o in r)/^\w/.test(o)&&("start"===o?e[o]=r[o]:t[o]=r[o]);return[e,t]};